  inputSchema: %*{
    "type": "object",
    "properties": {
      "summary": {
        "type": "string",
        "description": "Short summary of changes"
      },
      "ticket_id": {
        "type": "string",
        "description": "Ticket ID for this submission (optional, used in parallel mode)"
      }
    },
    "required": ["summary"]
  },
